(window.webpackJsonp=window.webpackJsonp||[]).push([[762],{757:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * // Definition for a Node.\\n * function Node(val,next,random) {\\n *    this.val = val;\\n *    this.next = next;\\n *    this.random = random;\\n * };\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{Node}</span> <span class=\\"hljs-variable\\">head</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{Node}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> copyRandomList = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">head</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> cur = head\\n  <span class=\\"hljs-keyword\\">while</span> (cur) {\\n    cur.next = <span class=\\"hljs-keyword\\">new</span> Node(cur.val, cur.next)\\n    cur = cur.next.next\\n  }\\n  cur = head\\n  <span class=\\"hljs-keyword\\">while</span> (cur) {\\n    <span class=\\"hljs-keyword\\">if</span> (cur.random) {\\n      cur.next.random = cur.random.next\\n    }\\n    cur = cur.next.next\\n  }\\n  cur = head\\n  <span class=\\"hljs-keyword\\">let</span> cloned = <span class=\\"hljs-keyword\\">new</span> Node()\\n  <span class=\\"hljs-keyword\\">let</span> cloned_cur = cloned\\n  <span class=\\"hljs-keyword\\">while</span> (cur) {\\n    <span class=\\"hljs-keyword\\">const</span> nn = cur.next.next\\n    cloned_cur = cloned_cur.next = cur.next\\n    cur = cur.next = nn\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> cloned.next\\n};\\n</code></pre>\\n","<pre class=\\"hljs\\"><code><span class=\\"hljs-string\\">\\"\\"\\"\\n# Definition for a Node.\\nclass Node(object):\\n    def __init__(self, val, next, random):\\n        self.val = val\\n        self.next = next\\n        self.random = random\\n\\"\\"\\"</span>\\n<span class=\\"hljs-class\\"><span class=\\"hljs-keyword\\">class</span> <span class=\\"hljs-title\\">Solution</span><span class=\\"hljs-params\\">(object)</span>:</span>\\n    <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">def</span> <span class=\\"hljs-title\\">copyRandomList</span><span class=\\"hljs-params\\">(self, head)</span>:</span>\\n        <span class=\\"hljs-string\\">\\"\\"\\"\\n        :type head: Node\\n        :rtype: Node\\n        \\"\\"\\"</span>\\n        <span class=\\"hljs-keyword\\">if</span> <span class=\\"hljs-keyword\\">not</span> head:<span class=\\"hljs-keyword\\">return</span> head\\n        node=head\\n        <span class=\\"hljs-keyword\\">while</span> node:\\n          nxt=node.next\\n          copy=Node(node.val,nxt,<span class=\\"hljs-literal\\">None</span>)\\n          node.next=copy\\n          node=node.next.next\\n        \\n        node=head\\n        <span class=\\"hljs-keyword\\">while</span> node:\\n          rd=node.random\\n          <span class=\\"hljs-keyword\\">if</span> rd:\\n            node.next.random=rd.next  \\n          node=node.next.next\\n          \\n        result=Node(<span class=\\"hljs-number\\">-1</span>,<span class=\\"hljs-literal\\">None</span>,<span class=\\"hljs-literal\\">None</span>)\\n        r=result\\n        node=head\\n        <span class=\\"hljs-keyword\\">while</span> node:\\n          copy=node.next\\n          nxt=node.next.next\\n          r.next=copy\\n          r=r.next\\n          node.next=nxt\\n          node=node.next\\n\\n        <span class=\\"hljs-keyword\\">return</span> result.next     \\n</code></pre>\\n"],"titleSlug":"copy-list-with-random-pointer","hasThinking":true,"thinking":"<hr>\\n<p>\u601d\u8def\uff1a</p>\\n<p>\u7b2c\u4e00\u6b21\u904d\u5386\uff1a\u5728\u6bcf\u4e00\u4e2a\u8282\u70b9\u540e\u9762\u6dfb\u52a0\u4e00\u4e2a<code>val</code>\u76f8\u540c\u7684\u8282\u70b9<code>copy</code>\u3002</p>\\n<p>\u7b2c\u4e8c\u6b21\u904d\u5386\uff1a\u5bf9\u6bcf\u4e00\u4e2a<code>\u65b0</code>\u8282\u70b9\u6dfb\u52a0<code>random</code>\u5c5e\u6027\uff0c<code>copy.random = oldNode.random.next</code></p>\\n<p>\u7b2c\u4e09\u6b21\u904d\u5386\uff1a\u5c06<code>copy</code>\u5355\u72ec\u63d0\u53d6\u51fa\uff0c\u5220\u9664\u539f\u94fe\u8868\u4e2d\u7684\u6240\u6709<code>copy</code>\u3002</p>\\n","content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u957f\u5ea6\u4e3a <code>n</code> \u7684\u94fe\u8868\uff0c\u6bcf\u4e2a\u8282\u70b9\u5305\u542b\u4e00\u4e2a\u989d\u5916\u589e\u52a0\u7684\u968f\u673a\u6307\u9488 <code>random</code> \uff0c\u8be5\u6307\u9488\u53ef\u4ee5\u6307\u5411\u94fe\u8868\u4e2d\u7684\u4efb\u4f55\u8282\u70b9\u6216\u7a7a\u8282\u70b9\u3002</p>\\n\\n<p>\u6784\u9020\u8fd9\u4e2a\u94fe\u8868\u7684\xa0<strong><a href=\\"https://baike.baidu.com/item/\u6df1\u62f7\u8d1d/22785317?fr=aladdin\\" target=\\"_blank\\">\u6df1\u62f7\u8d1d</a></strong>\u3002\xa0\u6df1\u62f7\u8d1d\u5e94\u8be5\u6b63\u597d\u7531 <code>n</code> \u4e2a <strong>\u5168\u65b0</strong> \u8282\u70b9\u7ec4\u6210\uff0c\u5176\u4e2d\u6bcf\u4e2a\u65b0\u8282\u70b9\u7684\u503c\u90fd\u8bbe\u4e3a\u5176\u5bf9\u5e94\u7684\u539f\u8282\u70b9\u7684\u503c\u3002\u65b0\u8282\u70b9\u7684 <code>next</code> \u6307\u9488\u548c <code>random</code> \u6307\u9488\u4e5f\u90fd\u5e94\u6307\u5411\u590d\u5236\u94fe\u8868\u4e2d\u7684\u65b0\u8282\u70b9\uff0c\u5e76\u4f7f\u539f\u94fe\u8868\u548c\u590d\u5236\u94fe\u8868\u4e2d\u7684\u8fd9\u4e9b\u6307\u9488\u80fd\u591f\u8868\u793a\u76f8\u540c\u7684\u94fe\u8868\u72b6\u6001\u3002<strong>\u590d\u5236\u94fe\u8868\u4e2d\u7684\u6307\u9488\u90fd\u4e0d\u5e94\u6307\u5411\u539f\u94fe\u8868\u4e2d\u7684\u8282\u70b9 </strong>\u3002</p>\\n\\n<p>\u4f8b\u5982\uff0c\u5982\u679c\u539f\u94fe\u8868\u4e2d\u6709 <code>X</code> \u548c <code>Y</code> \u4e24\u4e2a\u8282\u70b9\uff0c\u5176\u4e2d <code>X.random --\x3e Y</code> \u3002\u90a3\u4e48\u5728\u590d\u5236\u94fe\u8868\u4e2d\u5bf9\u5e94\u7684\u4e24\u4e2a\u8282\u70b9 <code>x</code> \u548c <code>y</code> \uff0c\u540c\u6837\u6709 <code>x.random --\x3e y</code> \u3002</p>\\n\\n<p>\u8fd4\u56de\u590d\u5236\u94fe\u8868\u7684\u5934\u8282\u70b9\u3002</p>\\n\\n<p>\u7528\u4e00\u4e2a\u7531\xa0<code>n</code>\xa0\u4e2a\u8282\u70b9\u7ec4\u6210\u7684\u94fe\u8868\u6765\u8868\u793a\u8f93\u5165/\u8f93\u51fa\u4e2d\u7684\u94fe\u8868\u3002\u6bcf\u4e2a\u8282\u70b9\u7528\u4e00\u4e2a\xa0<code>[val, random_index]</code>\xa0\u8868\u793a\uff1a</p>\\n\\n<ul>\\n\\t<li><code>val</code>\uff1a\u4e00\u4e2a\u8868\u793a\xa0<code>Node.val</code>\xa0\u7684\u6574\u6570\u3002</li>\\n\\t<li><code>random_index</code>\uff1a\u968f\u673a\u6307\u9488\u6307\u5411\u7684\u8282\u70b9\u7d22\u5f15\uff08\u8303\u56f4\u4ece\xa0<code>0</code>\xa0\u5230\xa0<code>n-1</code>\uff09\uff1b\u5982\u679c\u4e0d\u6307\u5411\u4efb\u4f55\u8282\u70b9\uff0c\u5219\u4e3a\xa0\xa0<code>null</code>\xa0\u3002</li>\\n</ul>\\n\\n<p>\u4f60\u7684\u4ee3\u7801 <strong>\u53ea</strong> \u63a5\u53d7\u539f\u94fe\u8868\u7684\u5934\u8282\u70b9 <code>head</code> \u4f5c\u4e3a\u4f20\u5165\u53c2\u6570\u3002</p>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/01/09/e1.png\\" style=\\"height: 138px; width: 680px;\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [[7,null],[13,0],[11,4],[10,2],[1,0]]\\n<strong>\u8f93\u51fa\uff1a</strong>[[7,null],[13,0],[11,4],[10,2],[1,0]]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/01/09/e2.png\\" style=\\"height: 111px; width: 680px;\\" /></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [[1,1],[2,1]]\\n<strong>\u8f93\u51fa\uff1a</strong>[[1,1],[2,1]]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/01/09/e3.png\\" style=\\"height: 119px; width: 680px;\\" /></strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = [[3,null],[3,0],[3,null]]\\n<strong>\u8f93\u51fa\uff1a</strong>[[3,null],[3,0],[3,null]]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 4\uff1a</strong></p>\\n\\n<pre>\\n<strong>\u8f93\u5165\uff1a</strong>head = []\\n<strong>\u8f93\u51fa\uff1a</strong>[]\\n<strong>\u89e3\u91ca\uff1a</strong>\u7ed9\u5b9a\u7684\u94fe\u8868\u4e3a\u7a7a\uff08\u7a7a\u6307\u9488\uff09\uff0c\u56e0\u6b64\u8fd4\u56de null\u3002\\n</pre>\\n\\n<p>\xa0</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li><code>0 <= n <= 1000</code></li>\\n\\t<li><code>-10000 <= Node.val <= 10000</code></li>\\n\\t<li><code>Node.random</code>\xa0\u4e3a\u7a7a\uff08null\uff09\u6216\u6307\u5411\u94fe\u8868\u4e2d\u7684\u8282\u70b9\u3002</li>\\n</ul>\\n","title":"138. \u590d\u5236\u5e26\u968f\u673a\u6307\u9488\u7684\u94fe\u8868","relatedTags":["\u54c8\u5e0c\u8868","\u94fe\u8868"],"difficult":"Middle","lang":["javascript","python"],"uniqueID":"138"}')}}]);